const payload = $input.item.json.body || $input.item.json;
const cliente = payload.cliente || 'GERAL';
const principios = payload.principios || [];
const friccoes = payload.friccoes || [];
const dividas = payload.dividas || [];
const documentos_mortos = payload.documentos_mortos || [];
const inconsistencias = payload.inconsistencias || [];
const ficou_no_ar = payload.ficou_no_ar || '';
const diretor_mencionou = payload.diretor_mencionou || '';
const data = payload.data || new Date().toLocaleDateString('pt-BR', {timeZone: 'America/Sao_Paulo'});
const hora = payload.hora || new Date().toLocaleTimeString('pt-BR', {timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit'});
const resumoPrincipios = principios.length > 0 ? principios.map(function(p, i) { return (i+1) + '. ' + p; }).join('\n') : 'Nenhum principio novo';
const resumoFriccoes = friccoes.length > 0 ? friccoes.map(function(f, i) { return (i+1) + '. ' + f; }).join('\n') : 'Nenhuma friccao';
const extraLinhas = [];
if (documentos_mortos.length > 0) extraLinhas.push('Docs mortos: ' + documentos_mortos.join(', '));
if (inconsistencias.length > 0) extraLinhas.push('Inconsistencias: ' + inconsistencias.join(', '));
if (ficou_no_ar) extraLinhas.push('Ficou no ar: ' + ficou_no_ar);
if (diretor_mencionou) extraLinhas.push('Diretor mencionou: ' + diretor_mencionou);
const extraBloco = extraLinhas.length > 0 ? '\n\n' + extraLinhas.join('\n') : '';
const texto = 'Sessao encerrada -- ' + data + ' ' + hora + '\nCliente: ' + cliente + '\n\nPrincipios (+' + principios.length + '):\n' + resumoPrincipios + '\n\nFriccoes (+' + friccoes.length + '):\n' + resumoFriccoes + '\n\nDividas: ' + dividas.length + extraBloco;
return [{ json: { cliente: cliente, data: data, hora: hora, texto: texto, principios: principios, friccoes: friccoes, dividas: dividas, documentos_mortos: documentos_mortos, inconsistencias: inconsistencias, ficou_no_ar: ficou_no_ar, diretor_mencionou: diretor_mencionou } }];
